import json
import re
import html
from datetime import datetime, timezone, timedelta
from urllib.request import Request, urlopen
from email.utils import parsedate_to_datetime
import xml.etree.ElementTree as ET

# ---- helpers ----
def _now_utc():
    return datetime.now(timezone.utc)

def _parse_dt(val):
    """Parse RFC2822 pubDate / ISO8601 / unix timestamp -> aware UTC datetime."""
    if not val:
        return None

    if isinstance(val, (int, float)):
        ts = float(val)
        if ts > 1e12:  # ms
            ts /= 1000.0
        return datetime.fromtimestamp(ts, tz=timezone.utc)

    s = str(val).strip()
    if not s:
        return None

    # RFC822/2822 (pubDate)
    try:
        dt = parsedate_to_datetime(s)
        if dt:
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=timezone.utc)
            return dt.astimezone(timezone.utc)
    except Exception:
        pass

    # ISO8601
    try:
        dt = datetime.fromisoformat(s.replace("Z", "+00:00"))
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=timezone.utc)
        return dt.astimezone(timezone.utc)
    except Exception:
        return None

def _strip_ns(tag: str) -> str:
    return tag.split("}", 1)[-1] if "}" in tag else tag

def _get_child_text(el, names):
    """Find first child whose localname in names; return stripped text."""
    for ch in list(el):
        if _strip_ns(ch.tag) in names:
            txt = (ch.text or "").strip()
            if txt:
                return txt
    return ""

def _get_atom_link(entry):
    for ch in list(entry):
        if _strip_ns(ch.tag) == "link":
            href = ch.attrib.get("href")
            if not href:
                continue
            rel = (ch.attrib.get("rel") or "").lower()
            if rel in ("", "alternate"):
                return href.strip()
    return ""

def _to_content_snippet(raw_html: str):
    """Convert description/content HTML -> plain text snippet (no length truncation)."""
    if not raw_html:
        return ""
    s = html.unescape(raw_html)
    s = re.sub(r"<[^>]+>", " ", s)   # strip tags
    s = re.sub(r"\s+", " ", s).strip()
    return s

def fetch_xml(url: str) -> str:
    req = Request(url, headers={"User-Agent": "n8n-rss-agent/1.0"})
    with urlopen(req, timeout=20) as r:
        return r.read().decode("utf-8", errors="replace")

def parse_feed(xml_text: str):
    """Return list of dicts with title/link/pubDate_raw/dt/content_raw."""
    root = ET.fromstring(xml_text)
    root_name = _strip_ns(root.tag).lower()

    items = []

    # RSS 2.0
    if root_name == "rss":
        channel = None
        for ch in list(root):
            if _strip_ns(ch.tag).lower() == "channel":
                channel = ch
                break
        if channel is None:
            return items

        for it in channel.findall(".//item"):
            title = _get_child_text(it, ["title"])
            link = _get_child_text(it, ["link"])
            pub_raw = _get_child_text(it, ["pubDate", "date", "updated"])
            # description / content:encoded (localname usually "encoded")
            desc = _get_child_text(it, ["description", "summary"])
            encoded = _get_child_text(it, ["encoded", "content"])  # cover content:encoded / content
            content_raw = encoded or desc

            dt = _parse_dt(pub_raw)
            items.append({
                "title": title,
                "link": link,
                "pubDate": pub_raw,
                "dt": dt,
                "content_raw": content_raw,
            })
        return items

    # Atom
    if root_name == "feed":
        for entry in root.findall(".//{*}entry"):
            title = _get_child_text(entry, ["title"])
            link = _get_atom_link(entry)
            pub_raw = _get_child_text(entry, ["published", "updated"])
            summ = _get_child_text(entry, ["summary", "content"])

            dt = _parse_dt(pub_raw)
            items.append({
                "title": title,
                "link": link,
                "pubDate": pub_raw,
                "dt": dt,
                "content_raw": summ,
            })
        return items

    return items

# ---- main ----
query = _query  # n8n Code Tool input

if not query or not str(query).strip():
    return json.dumps(
        {"error": "Provide JSON: {url, days?, start?, end?, max_items?}"},
        ensure_ascii=False
    )

cfg = json.loads(query)
url = cfg.get("url")
if not url:
    return json.dumps({"error": "Missing 'url'."}, ensure_ascii=False)

max_items = int(cfg.get("max_items", 20))

now = _parse_dt(cfg.get("now")) or _now_utc()
end = _parse_dt(cfg.get("end")) or now
start = _parse_dt(cfg.get("start"))

# if no explicit start provided, fall back to days
if start is None:
    days = int(cfg.get("days", 30))
    start = end - timedelta(days=days)

xml_text = fetch_xml(url)
raw_items = parse_feed(xml_text)

out = []
for it in raw_items:
    dt = it.get("dt")
    if not dt:
        continue
    if start <= dt <= end:
        out.append({
            "title": it.get("title", ""),
            "link": it.get("link", ""),
            "pubDate": it.get("pubDate", ""),
            "contentSnippet": _to_content_snippet(it.get("content_raw", "")),
        })

# sort by dt desc (we don't output dt, only use for sorting)
def _sort_key(x):
    # parse pubDate again for ordering fallback if needed
    return _parse_dt(x.get("pubDate")) or datetime.min.replace(tzinfo=timezone.utc)

out.sort(key=_sort_key, reverse=True)
out = out[:max_items]

return json.dumps(
    {
        "start": start.isoformat(),
        "end": end.isoformat(),
        "count": len(out),
        "items": out,
    },
    ensure_ascii=False
)
